14	type Incident = { cause: string; damages: Damage[] };
15	type QuoteStep = { op: "quote"; items: Item[] };
16	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
17	type Step = QuoteStep | ClaimStep;
18	type Scenario = { customer: Customer; steps: Step[] };
