20	const DEDUCTIBLE = 100;
21	const INSURANCE_VALUE: Record<string, number> = {
22	  sword: 1000,
23	  amulet: 600,
24	  rune: 250,
25	};
26	const CAP_MULTIPLIER = 2;
27	
28	const sum = (numbers: number[]): number =>
29	  numbers.reduce((acc, n) => acc + n, 0);
30	
31	// round up to whole G in MHPCO's favor, using epsilon to fight FP error
32	const roundUpInMHPCOFavor = (amount: number): number =>
33	  Math.ceil(amount - FP_EPSILON);
34	
35	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
36	const COMPONENT_BLOCK_SIZE = 3;
37	const COMPONENT_BLOCK_PRICE = 60;
38	
39	const countByType = (items: Item[]): Map<string, number> =>
40	  items.reduce(
41	    (acc, item) => acc.set(item.type, (acc.get(item.type) ?? 0) + 1),
42	    new Map<string, number>(),
43	  );
44	
45	const typeGroupPremium = (type: string, count: number): number =>
46	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE
47	    ? COMPONENT_BLOCK_PRICE
48	    : count * BASE_PREMIUM[type];
49	
50	const itemsBasePremium = (items: Item[]): number =>
51	  sum(
52	    Array.from(countByType(items), ([type, count]) =>
53	      typeGroupPremium(type, count),
54	    ),
55	  );
56	
57	type Rule<T> = { applies: (subject: T) => boolean; rate: number };
58	
59	const applicableRatesTotal = <T>(base: number, subject: T, rules: Rule<T>[]): number =>
60	  sum(rules.map((rule) => (rule.applies(subject) ? base * rule.rate : 0)));
61	
62	const CURSE_SURCHARGE_RATE = 0.5;
63	const HIGH_ENCHANTMENT_RATE = 0.3;
64	const HIGH_ENCHANTMENT_THRESHOLD = 5;
65	
66	const SURCHARGE_RULES: Rule<Item>[] = [
67	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE_RATE },
68	  {
69	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
70	    rate: HIGH_ENCHANTMENT_RATE,
71	  },
72	];
73	
74	const itemSurcharge = (item: Item): number =>
75	  applicableRatesTotal(BASE_PREMIUM[item.type], item, SURCHARGE_RULES);
76	
77	const itemSurcharges = (items: Item[]): number =>
78	  sum(items.map(itemSurcharge));
79	
80	const LOYALTY_DISCOUNT_RATE = 0.2;
81	const LOYALTY_YEARS_THRESHOLD = 2;
82	const FOLLOWUP_DISCOUNT_RATE = 0.15;
83	
84	type PolicyContext = { customer: Customer; isFollowup: boolean };
85	
86	const POLICY_MODIFIER_RULES: Rule<PolicyContext>[] = [
87	  { applies: () => true, rate: FIRST_INSURANCE_RATE },
88	  {
89	    applies: (ctx) => ctx.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
90	    rate: -LOYALTY_DISCOUNT_RATE,
91	  },
92	  { applies: (ctx) => ctx.isFollowup, rate: -FOLLOWUP_DISCOUNT_RATE },
93	];
94	
95	const policyModifiers = (policyBase: number, ctx: PolicyContext): number =>
96	  applicableRatesTotal(policyBase, ctx, POLICY_MODIFIER_RULES);
97	
98	const quote = ({ items }: QuoteStep, ctx: PolicyContext): { premium: number } => {
99	  const policyBase = itemsBasePremium(items);
100	  const total =
101	    policyBase +
102	    itemSurcharges(items) +
103	    policyModifiers(policyBase, ctx) +
104	    PROCESSING_FEE;
105	  return { premium: roundUpInMHPCOFavor(total) };
106	};
107	
108	type Policy = { items: Item[]; remainingCap: number };
109	
110	const policyInsuranceSum = (items: Item[]): number =>
111	  sum(items.map((item) => INSURANCE_VALUE[item.type]));
112	
113	const damagePayout = (damage: Damage): number =>
114	  Math.max(0, damage.amount - DEDUCTIBLE);
115	
116	const claim = (
117	  step: ClaimStep,
118	  policies: Policy[],
119	): { payout: number; remainingCap: number } => {
120	  const policy = policies[step.policy];
121	  const payout = sum(step.incident.damages.map(damagePayout));
122	  policy.remainingCap -= payout;
123	  return { payout, remainingCap: policy.remainingCap };
124	};
125	
126	const openPolicy = (items: Item[]): Policy => ({
127	  items,
128	  remainingCap: policyInsuranceSum(items) * CAP_MULTIPLIER,
129	});
130	
131	const processQuote = (
132	  step: QuoteStep,
133	  customer: Customer,
134	  policies: Policy[],
135	) => {
136	  const result = quote(step, { customer, isFollowup: policies.length > 0 });
137	  policies.push(openPolicy(step.items));
138	  return result;
139	};
140	
141	export const runScenario = (input: unknown): unknown => {
142	  const scenario = input as Scenario;
143	  const policies: Policy[] = [];
144	  const results = scenario.steps.map((step) =>
145	    step.op === "quote"
146	      ? processQuote(step, scenario.customer, policies)
147	      : claim(step, policies),
148	  );
149	  return { results };
150	};
